def generate_upload_url(event, context):
    body = json.loads(event['body'])
    filename = os.path.basename(body.get('filename', ''))[:255]
    if not filename:
        return {'statusCode': 400, 'body': '{"error": "Invalid filename"}'}

    tenant_id = event['requestContext']['authorizer']['tenant_id']
    upload_id = str(uuid4())
    key = f'{tenant_id}/evidence/{upload_id}/{filename}'

    url = s3.generate_presigned_url('put_object',
        Params={'Bucket': BUCKET, 'Key': key}, ExpiresIn=300)
    return {'statusCode': 200, 'body': json.dumps({'url': url, 'key': key})}

