RESTRICTED_BUILTINS = {
    'abs': abs, 'all': all, 'any': any, 'bool': bool,
    'dict': dict, 'enumerate': enumerate, 'float': float,
    'int': int, 'len': len, 'list': list, 'max': max,
    'min': min, 'print': print, 'range': range, 'round': round,
    'set': set, 'sorted': sorted, 'str': str, 'sum': sum, 'zip': zip,
}

def sandbox_node(state: AgentState):
    generated_code = state.get('generated_code', '')
    restricted_globals = {'__builtins__': RESTRICTED_BUILTINS}
    restricted_locals = {}
    try:
        exec(generated_code, restricted_globals, restricted_locals)
    except Exception as e:
        state['sandbox_result'] = {'error': str(e)}
    return state

